import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,e}from"./app-02133217.js";const p="/408CSFamily/assets/顺序栈共享存储空间-e2abf0d6.png",o={},t=e(`<h1 id="栈的顺序存储结构" tabindex="-1"><a class="header-anchor" href="#栈的顺序存储结构" aria-hidden="true">#</a> 栈的顺序存储结构</h1><p><code>顺序栈</code>：栈的顺序存储，利用一组地址连续的存储单元存放自栈底到栈顶的所有元素，同时<strong>附加一个用来指向当前栈顶位置的指针</strong></p><blockquote><p>指针指向栈顶（top）主要是因为栈在线性表的一端操作，操作的那端就是栈顶，方便操作。</p></blockquote><h2 id="顺序栈的存储类型" tabindex="-1"><a class="header-anchor" href="#顺序栈的存储类型" aria-hidden="true">#</a> 顺序栈的存储类型</h2><div class="language-cpp line-numbers-mode" data-ext="cpp"><pre class="language-cpp"><code><span class="token comment">// 定义栈中元素的最大个数</span>
<span class="token macro property"><span class="token directive-hash">#</span> <span class="token directive keyword">define</span> <span class="token macro-name">MaxSize</span> <span class="token expression"><span class="token number">50</span></span></span>

<span class="token comment">// 结构体定义</span>
<span class="token keyword">typedef</span> <span class="token keyword">struct</span><span class="token punctuation">{</span>
    ElemType data<span class="token punctuation">[</span>MaxSize<span class="token punctuation">]</span><span class="token punctuation">;</span>     <span class="token comment">// 存放栈中元素</span>
    <span class="token keyword">int</span> top<span class="token punctuation">;</span>                    <span class="token comment">// 栈顶指针</span>
<span class="token punctuation">}</span>SqStack<span class="token punctuation">;</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>假设存在顺序栈S，则：</p><ul><li>栈顶指针：S.top 初始化时设置S.top=-1</li><li>栈顶元素：S.data[S.top]，其中S.top为栈顶指针</li><li>进栈操作：栈不满时，栈顶指针+1，再送值到栈顶元素</li><li>出栈操作：栈非空时，先取栈顶元素值，再将栈顶指针-1</li><li>栈空条件：S.top=-1</li><li>栈满条件：S.top=MaxSize-1</li><li>栈长：S.top+1</li></ul><blockquote><p>Tips: 进栈先移动指针，避免占满，元素无法添加，出现外溢；出栈先取栈顶元素，保证指针永远指向栈顶。</p></blockquote><p>顺序栈的存储结构体定义可以很明显看出，顺序栈的入栈操作会受到数组上界(MaxSize)的约束。</p><p><strong>当对栈的最大使用空间估计不足时，容易出现栈上溢(外溢)，需要主动向用户报告反馈，避免出现错误；</strong></p><h2 id="顺序栈的基本运算" tabindex="-1"><a class="header-anchor" href="#顺序栈的基本运算" aria-hidden="true">#</a> 顺序栈的基本运算</h2><ul><li><code>InitStack(&amp;S)</code>: 初始化一个空栈<code>S</code>,栈顶指针初始化为-1</li><li><code>StackEmpty(S)</code>: 判断一个栈是否为空，如果栈空则返回<code>true</code>,否则返回<code>false</code></li><li><code>Push(&amp;S,x)</code>: 进栈，若栈未满，<code>x</code>进栈操作，插入到栈内成为<code>新的栈顶元素</code>。</li><li><code>Pop(&amp;S,&amp;x)</code>: 出栈，若栈非空，出栈操作，<strong>弹出栈顶元素</strong>，用指针<code>x</code>进行返回。</li><li><code>GetTop(S,&amp;x)</code>: 读栈顶元素，若栈<code>S</code>非空，用x返回栈顶元素。</li><li><code>ClearStack(&amp;S)</code>: 销毁栈，释放栈<code>S</code>占用的存储空间。</li></ul><h3 id="初始化" tabindex="-1"><a class="header-anchor" href="#初始化" aria-hidden="true">#</a> 初始化</h3><p><code>InitStack(&amp;S)</code>: 初始化一个空栈<code>S</code>,栈顶指针初始化为-1</p><div class="language-cpp line-numbers-mode" data-ext="cpp"><pre class="language-cpp"><code>
<span class="token keyword">void</span> <span class="token function">InitStack</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>S<span class="token punctuation">)</span><span class="token punctuation">{</span>
    <span class="token comment">// 栈顶指针-1</span>
    s<span class="token punctuation">.</span>top<span class="token operator">=</span><span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="栈空判断" tabindex="-1"><a class="header-anchor" href="#栈空判断" aria-hidden="true">#</a> 栈空判断</h3><p><code>StackEmpty(S)</code>: 判断一个栈是否为空，即：栈顶指针是否为-1，如果栈空则返回<code>true</code>,否则返回<code>false</code></p><div class="language-cpp line-numbers-mode" data-ext="cpp"><pre class="language-cpp"><code>
<span class="token keyword">bool</span> <span class="token function">StackEmpty</span><span class="token punctuation">(</span>S<span class="token punctuation">)</span><span class="token punctuation">{</span>
    <span class="token keyword">if</span><span class="token punctuation">(</span>S<span class="token punctuation">.</span>top<span class="token operator">==</span><span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
        <span class="token comment">// 栈空</span>
        <span class="token keyword">return</span> <span class="token boolean">true</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span><span class="token keyword">else</span><span class="token punctuation">{</span>
        <span class="token comment">// 栈非空</span>
        <span class="token keyword">return</span> <span class="token boolean">false</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="进栈" tabindex="-1"><a class="header-anchor" href="#进栈" aria-hidden="true">#</a> 进栈</h3><p><code>Push(&amp;S,x)</code>: 进栈，若栈未满，<code>x</code>进栈操作，插入到栈内成为<code>新的栈顶元素</code>。</p><div class="language-cpp line-numbers-mode" data-ext="cpp"><pre class="language-cpp"><code>
<span class="token keyword">bool</span> <span class="token function">Push</span><span class="token punctuation">(</span>SqStack <span class="token operator">&amp;</span>S<span class="token punctuation">,</span>ElemType x<span class="token punctuation">)</span><span class="token punctuation">{</span>
    <span class="token keyword">if</span><span class="token punctuation">(</span>S<span class="token punctuation">.</span>top<span class="token operator">==</span>MaxSize<span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
        <span class="token comment">// 栈满，返回false，元素无法进行进栈操作</span>
        <span class="token keyword">return</span> <span class="token boolean">false</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span><span class="token keyword">else</span><span class="token punctuation">{</span>
        <span class="token comment">// 可进栈，栈顶指针+1，再元素入栈</span>
        S<span class="token punctuation">.</span>data<span class="token punctuation">[</span><span class="token operator">++</span>S<span class="token punctuation">.</span>top<span class="token punctuation">]</span><span class="token operator">=</span>x<span class="token punctuation">;</span>
        
        <span class="token comment">// 入栈成功</span>
        <span class="token keyword">return</span> <span class="token boolean">true</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>注意：</p><ul><li>进栈先移动栈顶指针+1，再操作入栈元素</li><li><code>++i</code>是简写，先对变量i进行递加操作，再进行使用，即：先加后用</li></ul><h3 id="出栈" tabindex="-1"><a class="header-anchor" href="#出栈" aria-hidden="true">#</a> 出栈</h3><p><code>Pop(&amp;S,&amp;x)</code>: 出栈，若栈非空，出栈操作，<strong>弹出栈顶元素</strong>，用指针<code>x</code>进行返回。</p><div class="language-cpp line-numbers-mode" data-ext="cpp"><pre class="language-cpp"><code>
<span class="token keyword">bool</span> <span class="token function">Pop</span><span class="token punctuation">(</span>SqStack <span class="token operator">&amp;</span>S<span class="token punctuation">,</span>ElemType <span class="token operator">&amp;</span>x<span class="token punctuation">)</span><span class="token punctuation">{</span>
    <span class="token keyword">if</span><span class="token punctuation">(</span>S<span class="token punctuation">.</span>top<span class="token operator">==</span><span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
        <span class="token comment">// 栈空，无栈顶元素可出栈，返回false</span>
        <span class="token keyword">return</span> <span class="token boolean">false</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span><span class="token keyword">else</span><span class="token punctuation">{</span>
        <span class="token comment">// 栈非空，先元素出栈，再进行指针-1</span>
        x<span class="token operator">=</span>S<span class="token punctuation">.</span>data<span class="token punctuation">[</span>S<span class="token punctuation">.</span>top<span class="token operator">--</span><span class="token punctuation">]</span><span class="token punctuation">;</span>
        
        <span class="token comment">// 出栈成功，返回true</span>
        <span class="token keyword">return</span> <span class="token boolean">true</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>注意：</p><ul><li>出栈操作，先让元素出栈，获取栈顶元素，再移动指针-1</li><li><code>i--</code>是先使用变量i，再对变量做递减操作，即：先用后加（减）</li></ul><h3 id="读-获取-栈顶元素" tabindex="-1"><a class="header-anchor" href="#读-获取-栈顶元素" aria-hidden="true">#</a> 读（获取）栈顶元素</h3><p><code>GetTop(S,&amp;x)</code>: 读栈顶元素，若栈<code>S</code>非空，用x返回栈顶元素。</p><div class="language-cpp line-numbers-mode" data-ext="cpp"><pre class="language-cpp"><code>
<span class="token keyword">bool</span> <span class="token function">GetTop</span><span class="token punctuation">(</span>SqStack S<span class="token punctuation">,</span>ElemType <span class="token operator">&amp;</span>x<span class="token punctuation">)</span><span class="token punctuation">{</span>
    
    <span class="token keyword">if</span><span class="token punctuation">(</span>S<span class="token punctuation">.</span>top<span class="token operator">==</span><span class="token operator">-</span><span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
        <span class="token comment">// 栈空，无栈顶元素,返回false</span>
        <span class="token keyword">return</span> <span class="token boolean">false</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span><span class="token keyword">else</span><span class="token punctuation">{</span>
    
        <span class="token comment">// 通过栈顶指针，获取栈顶元素，赋值给变量x</span>
        x<span class="token operator">=</span>S<span class="token punctuation">.</span>data<span class="token punctuation">[</span>S<span class="token punctuation">.</span>top<span class="token punctuation">]</span><span class="token punctuation">;</span>
        
        <span class="token comment">// 读取栈顶元素成功，返回true</span>
        <span class="token keyword">return</span> <span class="token boolean">true</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>上面的这些操作都是基于栈顶指针初始化为<code>-1</code>的情况</strong></p><p>当栈顶指针初始化为<code>S.top=0</code>,相关操作操作会有区别：</p><ul><li>入栈： <code>S.data[S.top++]=x</code></li><li>出栈： <code>x=S.data[--S.top]</code></li></ul><p><strong>同时， 栈空、栈满条件也会有变化，要仔细对比揣摩</strong></p><h2 id="共享栈" tabindex="-1"><a class="header-anchor" href="#共享栈" aria-hidden="true">#</a> 共享栈</h2><p><code>共享栈</code>：利用栈底位置相对不变的特性，可以让两个顺序栈共享一个<code>一维存储空间</code>，将两个栈的栈底分别设置在共享空间的两端，两个栈顶则向共享空间的中间延伸</p><blockquote><p>Tips: 类似头对头，一致对外这种感觉，噗呲哈哈</p></blockquote><figure><img src="`+p+'" alt="顺序栈共享存储空间" tabindex="0" loading="lazy"><figcaption>顺序栈共享存储空间</figcaption></figure><p>在上面的共享栈结构图中，两个栈（0、1号顺序栈）的栈顶指针都指向栈顶元素</p><ul><li>0号栈栈顶指针<code>top=-1</code>时，0号栈为空</li><li>1号栈栈顶指针<code>top=MaxSize</code>时，1号栈为空</li></ul><p>当且仅当两个栈的栈顶指针相邻(<code>top1-top0=1</code>),可以判断共享栈栈满</p><h3 id="进栈-1" tabindex="-1"><a class="header-anchor" href="#进栈-1" aria-hidden="true">#</a> 进栈</h3><blockquote><p>进栈：先移动指针，后进行赋值</p></blockquote><ul><li>当0号栈进栈时，0号栈栈顶指针top0<code>先加1后赋值</code></li><li>当1号栈进栈时，0号栈栈顶指针top1<code>先减1后赋值</code></li></ul><h3 id="出栈-1" tabindex="-1"><a class="header-anchor" href="#出栈-1" aria-hidden="true">#</a> 出栈</h3><blockquote><p>出栈：先进行赋值，后移动指针</p></blockquote><ul><li>当0号栈进栈时，0号栈栈顶指针top0<code>先赋值后减1</code></li><li>当1号栈进栈时，0号栈栈顶指针top1<code>先赋值后加1</code></li></ul><p>共享栈能够更有效的利用存储空间，两个栈空间进行相互调节。只有当这个存储空间（即：共享空间）被占满时才会发生上溢。存取数据的时间复杂度都为O(1)，在栈顶操作。</p><p><strong>共享栈对存取效率没有什么影响</strong></p>',50),c=[t];function i(l,d){return s(),a("div",null,c)}const k=n(o,[["render",i],["__file","stack-sequential-storage.html.vue"]]);export{k as default};
